// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
   const inputDate = new Date(item.json.timestamp);
    let year = inputDate.getUTCFullYear();
    let month = inputDate.getUTCMonth(); // 0-indexed (Jan = 0)
    let day = inputDate.getUTCDate();

  month -= 1;
  if (month < 0) {
    month = 11;
    year -= 1;
}

const maxDayInMonth = new Date(Date.UTC(year, month + 1, 0)).getUTCDate();
const safeDay = Math.min(day, maxDayInMonth);

const previousMonthDate = new Date(Date.UTC(year, month, safeDay, inputDate.getUTCHours(), inputDate.getUTCMinutes(), inputDate.getUTCSeconds()));




return [
  {
    json: {
      previousMonthTimestamp: previousMonthDate.toISOString()
    }
  }
];
}

const output= $input.all().map(item => {
  const json = item.json;

  return {
      saleOrder: json.fullName,
      createdOn: json.createdOn.split("T")[0],
      inTaxTotal: parseFloat(json.inTaxTotal),
      amountInvoiced: parseFloat(json.amountInvoiced),
      overdueAmount: parseFloat(json.inTaxTotal) - parseFloat(json.amountInvoiced)
    }

});
  return[ { overdue:output}]
